const emojiFallback: Partial<Record<TIconName, string>> = {
  history: '📖',
  back: '←',
  share: '↗',
  mic: '🎤',
  close: '✕',
  settings: '⚙️',
  'chevron-right': '→',
  'thumbs-up': '👍',
  'thumbs-down': '👎',
  info: 'ℹ️',
};

/**
 * 아이콘 컴포넌트 — SVG 기반 (미지원 아이콘은 이모지 폴백)
 * @author Kimd0ng
 */
export const Icon: React.FC<IconProps> = ({ name, size = 20, color = DEFAULT_COLOR, style }) => {
  const svgRenderer = svgIcons[name];
  const emoji = emojiFallback[name] ?? '•';

  return (
    <View style={style}>
      {svgRenderer
        ? svgRenderer(color, size)
        : (
          <RNText style={{ fontSize: size, color, textAlign: 'center' }}>
            {emoji}
          </RNText>
        )
      }
    </View>
  );
};
